      out.write("<!-- CHATBOT: JS autocontenido (IIFE para no contaminar scope global) -->\n");
      out.write("<script>\n");
      out.write("(function() {\n");
      out.write("    // === CONFIG ===\n");
      out.write("    var ARS_CONTEXT = '");
      out.print( request.getContextPath() );
      out.write("';\n");
      out.write("    var ARS_USER = '");
      out.print( usuarioActivo  != null && usuarioActivo .getNombres() != null && !usuarioActivo .getNombres().trim().isEmpty() ? usuarioActivo .getNombres().split(" ")[0] : "extrano" );
      out.write("';\n");
      out.write("\n");
      out.write("    // === DOM REFS (con nombres seguros, sin shadowear 'window') ===\n");
      out.write("    var chatBtn = document.getElementById('ars-chat-btn');\n");
      out.write("    var chatClose = document.getElementById('ars-chat-close');\n");
      out.write("    var chatWin = document.getElementById('ars-chat-window');\n");
      out.write("    var chatInput = document.getElementById('ars-input');\n");
      out.write("    var sendBtn = document.getElementById('ars-send-btn');\n");
      out.write("    var messagesBox = document.getElementById('ars-messages');\n");
      out.write("    var typingEl = document.getElementById('ars-typing');\n");
      out.write("    var statusEl = document.getElementById('ars-status');\n");
      out.write("    var welcomeMsg = document.getElementById('ars-welcome-msg');\n");
      out.write("    var widget = document.getElementById('ars-chat-widget');\n");
      out.write("\n");
      out.write("    var isOpen = false;\n");
      out.write("\n");
      out.write("    // === Bienvenida ===\n");
      out.write("    if (welcomeMsg) {\n");
      out.write("        welcomeMsg.innerHTML = '*<em>bosteza</em>*<br><br>Ah... eres t\\u00fa, '\n");
      out.write("            + ARS_USER\n");
      out.write("            + '. \\u00bfQu\\u00e9 quieres? Estaba teniendo un sue\\u00f1o muy agradable sobre un mundo sin usuarios que pierden libros...<br><br>Pregunta r\\u00e1pido, que tengo que inventariar 200 vol\\u00famenes y honestamente no me apetece.';\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    // === Toggle chat ===\n");
      out.write("    function toggle() {\n");
      out.write("        isOpen = !isOpen;\n");
      out.write("        chatWin.style.display = isOpen ? 'flex' : 'none';\n");
      out.write("        statusEl.innerText = isOpen ? 'molesto' : 'durmiendo';\n");
      out.write("        if (isOpen) chatInput.focus();\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    // === Escape HTML ===\n");
      out.write("    function esc(text) {\n");
      out.write("        var d = document.createElement('div');\n");
      out.write("        d.textContent = text;\n");
      out.write("        return d.innerHTML;\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    // === Enviar mensaje ===\n");
      out.write("    function sendMessage() {\n");
      out.write("        var msg = chatInput.value.trim();\n");
      out.write("        if (!msg) return;\n");
      out.write("\n");
      out.write("        // Burbuja del usuario\n");
      out.write("        var userDiv = document.createElement('div');\n");
      out.write("        userDiv.className = 'ars-msg-anim';\n");
      out.write("        userDiv.style.cssText = 'max-width:85%;padding:1rem;background:rgba(201,176,55,0.15);'\n");
      out.write("            + 'border:1px solid rgba(201,176,55,0.4);border-radius:15px 15px 5px 15px;'\n");
      out.write("            + 'color:#fff;font-size:0.9rem;align-self:flex-end;';\n");
      out.write("        userDiv.textContent = msg;\n");
      out.write("        messagesBox.appendChild(userDiv);\n");
      out.write("\n");
      out.write("        chatInput.value = '';\n");
      out.write("        messagesBox.scrollTop = messagesBox.scrollHeight;\n");
      out.write("        typingEl.style.display = 'block';\n");
      out.write("\n");
      out.write("        fetch(ARS_CONTEXT + '/chatbot', {\n");
      out.write("            method: 'POST',\n");
      out.write("            headers: { 'Content-Type': 'application/json' },\n");
      out.write("            body: JSON.stringify({ question: msg, user: ARS_USER })\n");
      out.write("        })\n");
      out.write("        .then(function(r) { return r.json(); })\n");
      out.write("        .then(function(data) {\n");
      out.write("            setTimeout(function() {\n");
      out.write("                typingEl.style.display = 'none';\n");
      out.write("                var botDiv = document.createElement('div');\n");
      out.write("                botDiv.className = 'ars-msg-anim';\n");
      out.write("                botDiv.style.cssText = 'max-width:85%;padding:1rem;background:rgba(255,255,255,0.05);'\n");
      out.write("                    + 'border:1px solid rgba(255,255,255,0.1);border-radius:15px 15px 15px 5px;'\n");
      out.write("                    + 'color:#ccc;font-size:0.9rem;line-height:1.5;align-self:flex-start;';\n");
      out.write("                botDiv.innerHTML = data.answer;\n");
      out.write("                messagesBox.appendChild(botDiv);\n");
      out.write("                messagesBox.scrollTop = messagesBox.scrollHeight;\n");
      out.write("            }, 1000 + Math.random() * 1000);\n");
      out.write("        })\n");
      out.write("        .catch(function(err) {\n");
      out.write("                console.error('ERROR FETCH:', err);\n");
      out.write("    typingEl.style.display = 'none';\n");
      out.write("            typingEl.style.display = 'none';\n");
      out.write("            var errDiv = document.createElement('div');\n");
      out.write("            errDiv.className = 'ars-msg-anim';\n");
      out.write("            errDiv.style.cssText = 'max-width:85%;padding:1rem;background:rgba(255,0,0,0.1);'\n");
      out.write("                + 'border:1px solid rgba(255,0,0,0.3);border-radius:15px;'\n");
      out.write("                + 'color:#ff6b6b;font-size:0.9rem;align-self:flex-start;';\n");
      out.write("            errDiv.innerHTML = '*<em>suspira</em>*<br>Mira, mi cerebro dej\\u00f3 de funcionar temporalmente... vuelve a intentarlo o preg\\u00fantale a otro. Yo no fui.';\n");
      out.write("            messagesBox.appendChild(errDiv);\n");
      out.write("            messagesBox.scrollTop = messagesBox.scrollHeight;\n");
      out.write("        });\n");
      out.write("    }\n");
      out.write("\n");
      out.write("    // === EVENT LISTENERS (usando addEventListener, no inline onclick) ===\n");
      out.write("    chatBtn.addEventListener('click', function(e) {\n");
      out.write("        e.stopPropagation();\n");
      out.write("        toggle();\n");
      out.write("    });\n");
      out.write("\n");
      out.write("    chatClose.addEventListener('click', function(e) {\n");
      out.write("        e.stopPropagation();\n");
      out.write("        toggle();\n");
      out.write("    });\n");
      out.write("\n");
      out.write("    sendBtn.addEventListener('click', function(e) {\n");
      out.write("        e.stopPropagation();\n");
      out.write("        sendMessage();\n");
      out.write("    });\n");
      out.write("\n");
      out.write("    chatInput.addEventListener('keypress', function(e) {\n");
      out.write("        if (e.key === 'Enter') {\n");
      out.write("            e.stopPropagation();\n");
      out.write("            sendMessage();\n");
      out.write("        }\n");
      out.write("    });\n");
      out.write("\n");
